                  <div style={{position:"absolute",top:2,left:impostazioni.campiObbligatori[k]?22:2,width:20,height:20,borderRadius:"50%",background:"#fff",transition:"left 0.2s",boxShadow:"0 1px 3px rgba(0,0,0,0.2)"}}/>
