    +"</tbody><tfoot><tr style='font-weight:700;color:#DC2626'><td colspan='3'>TOTALE NOTA DI CREDITO</td><td style='text-align:right'>−€ "+tot.toFixed(2)+"</td></tr></tfoot></table>"
